def perceive(data):
    d = data if isinstance(data, dict) else {}
    out = {}
    if "target_reduction_kw" in d:
        out["target_reduction_kw"] = float(d["target_reduction_kw"])
    if "incentive_rate" in d:
        out["incentive_rate"] = float(d["incentive_rate"])
    return out
